const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;

const itemBasePremium = (item: Record<string, unknown>): number => {
  if (item.type === "sword") return 100;
  return 0;
};

const quotePremium = (items: Array<Record<string, unknown>>): number => {
  const baseSum = items.reduce((sum, item) => sum + itemBasePremium(item), 0);
  const firstInsuranceSurcharge = baseSum * FIRST_INSURANCE_SURCHARGE_RATE;
  return Math.ceil(baseSum + firstInsuranceSurcharge + PROCESSING_FEE);
};

export const runScenario = (scenario: Scenario): ScenarioResult => {
  const results = scenario.steps.map((step) => {
    if (step.op === "quote") {
      return { premium: quotePremium(step.items) };
    }
    return { payout: 0, remainingCap: 0 };
  });
  return { results };
};
